def flatten_dict(data):
    result = {}
    def _flatten(d, prefix=''):
        for key, value in d.items():
            new_key = f"{prefix}.{key}" if prefix else key
            if isinstance(value, dict):
                if value:
                    _flatten(value, new_key)
            else:
                result[new_key] = value
    _flatten(data)
    return result
