def smallest_covering_window(text, required):
    from collections import Counter

    need = Counter(required)
    if not need:
        return ""

    required_types = len(need)
    have = Counter()
    satisfied = 0

    best_len = float('inf')
    best_start = -1

    left = 0
    for right, ch in enumerate(text):
        if ch in need:
            have[ch] += 1
            if have[ch] == need[ch]:
                satisfied += 1

        while satisfied == required_types:
            window_len = right - left + 1
            if window_len < best_len:
                best_len = window_len
                best_start = left

            left_ch = text[left]
            if left_ch in need:
                if have[left_ch] == need[left_ch]:
                    satisfied -= 1
                have[left_ch] -= 1
            left += 1

    if best_start == -1:
        return ""
    return text[best_start:best_start + best_len]
